{"name": "replace_function", "arguments": {"path": "llm/q1/core/handlers.py", "func_name": "_validate_python_with_context", "content": "    def _validate_python_with_context(self, source):
        try:
            ast.parse(source)
            return True, "OK"
        except SyntaxError as e:
            source_lines = source.splitlines()
            line_no = e.lineno or 0
            start = max(line_no - 2, 1)
            end = min(line_no + 2, len(source_lines))
            context = []
            for idx in range(start, end + 1):
                marker = ">" if idx == line_no else " "
                context.append(f"{marker} {idx}: {source_lines[idx - 1]}")
            context_str = "\n".join(context)
            return False, (
                f"구문 오류 발생: '{e.msg}' (위치: {e.lineno}행, {e.offset}열)\n"
                f"주변 문맥:\n{context_str}\n"
                f"문제가 발생한 줄: {source_lines[line_no - 1]}"
            )
        except Exception as e:
            return False, f"알 수 없는 코드 검증 에러: {str(e)}""}}

