{"name": "replace_function", "arguments": {"path": "llm/q1/core/handlers.py", "func_name": "_resolve_path", "content": "    def _resolve_path(self, path):
        if not path:
            path = "."
        clean_path = path.lstrip('/')
        if clean_path.startswith('llm/llm/'):
            clean_path = clean_path.replace('llm/llm/', 'llm/', 1)
        elif clean_path.startswith('llm/'):
            clean_path = clean_path[len('llm/'):]  # Remove redundant 'llm/' prefix if present
        elif not clean_path.startswith(self.project_root):
            clean_path = os.path.join(self.project_root, clean_path)

        resolved_path = os.path.abspath(clean_path)
        normalized_path = os.path.normpath(resolved_path)
        project_root = os.path.abspath(self.project_root)

        if os.path.commonpath([project_root, normalized_path]) != project_root:
            raise ValueError(f"Attempted path traversal outside project root: {path} resolved to {normalized_path}")

